  `dob` datetime(3) DEFAULT NULL,
  `height` int(11) DEFAULT NULL,
  `weight` int(11) DEFAULT NULL,
  `religion` varchar(191) DEFAULT NULL,
  `caste` varchar(191) DEFAULT NULL,
  `motherTongue` varchar(191) DEFAULT NULL,
  `education` varchar(191) DEFAULT NULL,
  `profession` varchar(191) DEFAULT NULL,
  `income` varchar(191) DEFAULT NULL,
  `country` varchar(191) DEFAULT NULL,
  `state` varchar(191) DEFAULT NULL,
  `city` varchar(191) DEFAULT NULL,
  `aboutMe` text DEFAULT NULL,
  `maritalStatus` enum('NEVER_MARRIED','DIVORCED','WIDOWED','SEPARATED') NOT NULL DEFAULT 'NEVER_MARRIED',
  `smoking` enum('NO','OCCASIONALLY','YES') NOT NULL DEFAULT 'NO',
