  `complexion` varchar(191) DEFAULT NULL,
  `bodyType` varchar(191) DEFAULT NULL,
  `fatherOccupation` varchar(191) DEFAULT NULL,
  `motherOccupation` varchar(191) DEFAULT NULL,
  `siblings` int(11) DEFAULT NULL,
  `familyType` varchar(191) DEFAULT NULL,
  `familyStatus` varchar(191) DEFAULT NULL,
  `partnerAgeMin` int(11) DEFAULT NULL,
  `partnerAgeMax` int(11) DEFAULT NULL,
  `partnerHeightMin` int(11) DEFAULT NULL,
  `partnerHeightMax` int(11) DEFAULT NULL,
  `partnerReligion` varchar(191) DEFAULT NULL,
  `partnerEducation` varchar(191) DEFAULT NULL,
  `partnerLocation` varchar(191) DEFAULT NULL,
  `horoscopeSign` varchar(191) DEFAULT NULL,
  `manglik` varchar(191) DEFAULT 'No',
  `hidePhone` tinyint(1) NOT NULL DEFAULT 0,
  `hidePhoto` tinyint(1) NOT NULL DEFAULT 0,
  `profileComplete` int(11) NOT NULL DEFAULT 0,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  `amritdhari` varchar(191) DEFAULT NULL,
  `gotra` varchar(191) DEFAULT NULL,
  `kundliMatch` varchar(191) DEFAULT 'Not Required',
  `nakshatra` varchar(191) DEFAULT NULL,
  `sect` varchar(191) DEFAULT NULL,
  `subCaste` varchar(191) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

